INSERT INTO public.photos VALUES (23514, 'Colegio Escolapias 1930', 'Patio del colegio de MM. Escolapias. Imagen del antiguo patio del colegio de Santo Tom├ís de Villanueva y San Jorge, de los PP. Agustinos Observantes, sito en la plazuela de la Manter├¡a. Asociado a la f├íbrica de la iglesia y dem├ís dependencias colegiales de esta Orden, fue realizado a finales del siglo XVII en limpias formas barrocas, y ladrillo como material fundamental. En 1883 fue adquirido por las MM. Escolapias, que realizaron en ├®l varias intervenciones, de resultas de las cuales este viejo patio se qued├│ por el camino de la nada. Fuente visual: Foto R. Saus, en www.todocoleccion.net/', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65301200, -0.88323900, '0101000020E6100000E3A7716F7E43ECBFA1F2AFE595D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25008074384.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25008074384.webp', 'https://www.flickr.com/photos/zaragozaantigua/25008074384/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23519, 'Calle Galo Ponte 2006', 'Foto: Jos├® Miguel Marco. Vista de la calle de Galo Ponte, con el palacio de los Luna en el Coso Alto a la izquierda, y a la derecha el solar que albergar├í desde 2012 el nuevo edificio de la Audiencia Provincial de Zaragoza, dejando al palacio como sede del Tribunal Superior de Justicia de Arag├│n. Fuente: Heraldo de Arag├│n.', 2006, 2006, 2006, 'Siglo XXI', 'CENTRO', 41.65399200, -0.88324200, '0101000020E610000027840EBA8443ECBF3EEC8502B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31332067263.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31332067263.webp', 'https://www.flickr.com/photos/zaragozaantigua/31332067263/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23521, 'Coso Alto 1874', 'Dibujo a tinta y aguada que representa el patio interior de la casa situada frente a la puerta del palacio de los condes de Morata, en el Coso Alto. Posiblemente se trate de la antigua casa del siglo XV-XVI que a principios del siglo XVIII fuera del tesorero de la Real Audiencia, Vicente Jim├®nez de Bagu├®s. Desaparecida.', 1874, 1874, 1874, 'Siglo XIX', 'CENTRO', 41.65385100, -0.88382000, '0101000020E6100000809F71E14048ECBF7CBABA63B1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32124507516.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32124507516.webp', 'https://www.flickr.com/photos/zaragozaantigua/32124507516/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23522, 'Vista desde La Adri├ítica 2011', 'Foto: Oliver Duch. Vista desde el edificio La Adri├ítica, en el Coso Alto 34, de la evoluci├│n de las obras de la nueva Audiencia de Zaragoza, a finales de septiembre de 2011. Tras las redes, se puede ver la c├║pula geod├®sica del museo Pablo Gargallo, y m├ís all├í del puente de Santiago, tambi├®n en obras para el paso del tranv├¡a, la margen izquierda hasta el Parque Goya. Fuente: Heraldo de Arag├│n.', 2011, 2011, 2011, 'Siglo XXI', 'CENTRO', 41.65426500, -0.88312200, '0101000020E61000007E198C118942ECBF6FF59CF4BED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37771244134.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37771244134.webp', 'https://www.flickr.com/photos/zaragozaantigua/37771244134/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23526, 'Plaza de San Roque c.1935', 'Imagen centrada en la barroca f├íbrica en ladrillo de la iglesia de la Manter├¡a, que formara parte del antiguo colegio de Santo Tom├ís de Villanueva, y que desde 1883 formaba parte del anexo colegio de las madres escolapias. A la derecha, la calle de Agust├¡n Palomeque. En su fuente original, esta imagen aparece identificada como "fachada edificio barroco" y localizada en La Almunia de Do├▒a Godina. En GAZA nos hemos permitido reubicarla en su hist├│rico emplazamiento zaragozano.', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.65319400, -0.88314400, '0101000020E61000007313B534B742ECBFC2F869DC9BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50111563083.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50111563083.webp', 'https://www.flickr.com/photos/zaragozaantigua/50111563083/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23527, 'Audiencia Provincial 1895', 'Imagen capturada en el patio de la gran casa de mediados del siglo XVI de los Luna o Morata, que en 1725 fue donada por el conde de Perelada al rey Felipe V y habilitada poco despu├®s como residencia del capit├ín general de Arag├│n. Entre 1809 y 1813 fue la residencia del mariscal Jean Lannes, responsable de la administraci├│n francesa ocupante. En 1814, recuperada la normalidad del Antiguo R├®gimen, fue promovida a sede de la Audiencia Provincial, funci├│n que perdura en la actualidad. Centra la escena el monumento labrado por el escultor Carlos Palao en 1885 y dedicado a la Justicia. El aspecto del patio fue radicalmente transformado en la reforma proyectada por el arquitecto Regino Borobio Ojeda y desarrollada entre 1921 y 1929. En la actualidad, este bulto redondo se encuentra orillado junto a la escalera noble de la izquierda, si bien en un pedestal m├ís peque├▒o y desprovisto de ornamentaci├│n.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.65413200, -0.88344400, '0101000020E6100000191EFB592C45ECBF2FA2ED98BAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50123168928.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50123168928.webp', 'https://www.flickr.com/photos/zaragozaantigua/50123168928/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23528, 'Coso Alto c.1931', 'Imagen capturada desde la altura de la antigua Casa de las Monas y centrada en el arranque del tramo alto del Coso. A la izquierda inaugura la calle el edificio que alberga a la Audiencia Territorial, hasta la hom├│nima calle tras la que comienzan los inmuebles desde el n┬║ 3. A la derecha, tramo del lado de los pares, desde el inmediato y chaflanero n┬║ 8 que albergaba la consulta del dentista Luis Mundi, y el espacioso local comercial de Eusebio Omist, que por la parte trasera llegaba hasta el n┬║ 5 de la calle de Agust├¡n Palomeque, y en el que destacaba la tienda de ropa blanca "El Beb├®". En primer t├®rmino, curvea hacia la calle de Juan Jim├®nez Cerd├ín el tendido tranviario de la reciente l├¡nea 7. Ayuntamiento-Portillo.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65395100, -0.88377700, '0101000020E6100000AE9FFEB3E647ECBFDF1797AAB4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50704847663.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50704847663.webp', 'https://www.flickr.com/photos/zaragozaantigua/50704847663/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23529, 'Plaza de San Roque 1874', 'Imagen capturada en la plaza o plazuela de San Roque y centrada en la fachada de la antigua iglesia del colegio de Santo Tom├ís de Villanueva, llamada de la Manter├¡a por albergar tambi├®n a la cofrad├¡a de los manteros. Tras la exclaustraci├│n del inmueble en 1835, ├®ste pas├│ por dispares usos como almac├®n de grano y f├íbrica de harina para el ramo de la Guerra durante la primera guerra civil carlista, adem├ís de cuartel; a mediados de siglo la iglesia fue parroquia castrense, y el colegio acogi├│ un correccional de mujeres. En el tiempo en que fue realizada esta fotograf├¡a, era parque de artiller├¡a de la milicia y almac├®n de provisiones. En la imagen y a la derecha, vista parcial del lado de los impares de la inmediata calle de Agust├¡n de Lezo Palomeque, antigua de la Manter├¡a.', 1874, 1874, 1874, 'Siglo XIX', 'CENTRO', 41.65320200, -0.88320800, '0101000020E61000002219726C3D43ECBF45D7851F9CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51413822047.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51413822047.webp', 'https://www.flickr.com/photos/zaragozaantigua/51413822047/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23530, 'Coso Alto 1890', 'Coloreada imagen capturada desde la altura de la central de los tel├®fonos urbanos y centrada en el principio del tramo alto del Coso, donde destaca la gran fachada de la Audiencia Territorial con su quiosco de prensa en la puerta. A la izquierda la calle de Juan Jim├®nez Cerd├ín, y a la derecha la calle de la Audiencia y el arranque del inmueble del n┬║ 3 del Coso, en cuyos bajos se abr├¡a la "Gran Sastrer├¡a El Non Plus Ultra", especializada en ropa eclesi├ística. Sobre el firme, v├¡as de la l├¡nea Circunvalaci├│n por donde circulaban coches arrastrados por caballer├¡as.', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.65399600, -0.88375500, '0101000020E6100000B9A5D590B847ECBF7FDB1324B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51423854245.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51423854245.webp', 'https://www.flickr.com/photos/zaragozaantigua/51423854245/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23533, 'Coso alto 1878', 'Imagen capturada por el fot├│grafo villanovense Gregorio Sabat├® F├®rriz e integrada en el ├ílbum "Vistas de Zaragoza", centrada en la imponente fachada del original palacio de los Luna del siglo XVI, luego de los condes de Morata y finalmente de los condes de Peralada, que en 1725 donaron al rey Felipe V para que fuera su residencia Real durante sus estancias en la ciudad. Mientras tanto, ejerc├¡a de residencia del Capit├ín General y presidente de la Real Audiencia. En 1834 fueron creadas las Audiencias Territoriales como tribunal superior de Justicia de Distrito para causas civiles y criminales, y este edificio se convirti├│ en su sede. En 1882 esta instituci├│n fue reconvertida en Audiencia Territorial, con menos funciones. En la imagen, el inmueble sito en el arranque a la izquierda del tramo alto del Coso desde la antigua Casa de las Monas localizada entre las calles de Juan Jim├®nez Cerd├ín y de las Escuelas P├¡as. La fachada se muestra con su hechura original, antes de la intervenci├│n que en los a├▒os 20 del siglo XX le confiri├│ su actual aspecto. Destaca su m├ís que interesante portada de ingreso, flanqueada por las grandes figuras de los h├®roes mitol├│gicos H├®rcules y Teseo. Su tama├▒o hizo que popularmente fueran denominados como "gigantes", y su actitud llev├│ incluso a bautizarlos castizamente como "que te zurro" y "que te arreo", lo que referido a una instalaci├│n donde se imparte Justicia, resulta cuando menos inquietante, sobre todo si no tienes los contactos sociales adecuados.', 1878, 1878, 1878, 'Siglo XIX', 'CENTRO', 41.65402800, -0.88372300, '0101000020E6100000E222F7747547ECBF8A558330B7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54762763419.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54762763419.webp', 'https://www.flickr.com/photos/zaragozaantigua/54762763419/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23992, 'Teatro Iris 1942', 'Grupo de siete elefantes en el escenario del Teatro Iris, durante una representaci├│n circense. Fuente: Artigrama, 1995', 1942, 1942, 1942, 'Anos 40', 'CENTRO', 41.65163900, -0.88518800, '0101000020E610000005F9D9C87553ECBF2AE620E868D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19359846658.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19359846658.webp', 'https://www.flickr.com/photos/zaragozaantigua/19359846658/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24061, 'Teatro Fleta 2005', 'Entre 2001 y 2005 se realizaron excavaciones arqueol├│gicas en el subsuelo del antiguo Teatro Fleta. Se hallaron restos de los siglos XI al XV. En la foto, prospecciones en el patio de butacas, bajo una carpa provisional. Fuente visual: www.cdl-aragon.es/', 2005, 2005, 2005, 'Siglo XXI', 'CENTRO', 41.65181200, -0.88507700, '0101000020E610000029232E008D52ECBFF7915B936ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32302739431.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32302739431.webp', 'https://www.flickr.com/photos/zaragozaantigua/32302739431/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24067, 'Coso Alto 1975', 'Oto├▒al imagen de la comparsa de los diez gigantes en el arranque del Coso Alto: Rey, Reina, Duque, Duquesa, Chino, Negra, Don Quijote, Dulcinea, Bearn├®s, y Bearnesa. La cabezuda Forana saluda a algunos pardales. Al fondo, a la izquierda, el colegio de los Escolapios, y la manzana entre Escuelas P├¡as, y Cerd├ín. En el centro, la Audiencia, y la calle Galo Ponte. A su derecha, el antiguo n┬║ 3 del Coso, luego derribado, y despu├®s, el n┬║ 5, con Drogas Alfonso en sus bajos. A la derecha, el n┬║ 7, y un pedazo del saliente que anuncia el ingreso al Cine Coso. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1975, 1975, 1975, 'Anos 70', 'CENTRO', 41.65369300, -0.88326000, '0101000020E6100000C1ADBB79AA43ECBFE34F5436ACD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33577360015.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33577360015.webp', 'https://www.flickr.com/photos/zaragozaantigua/33577360015/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24973, 'Coso Alto 1942', 'Foto de 21 de mayo de 1942, tomada en el Coso Alto de Zaragoza, a la altura de la Audiencia. Una joven pasea en bicicleta. Al fondo, los Escolapios. Fuente: www.facebook.com/photo.php?fbid=712500898834172&set=g...', 1942, 1942, 1942, 'Anos 40', 'CENTRO', 41.65378700, -0.88358800, '0101000020E6100000E46A64575A46ECBF65C6DB4AAFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19440935908.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19440935908.webp', 'https://www.flickr.com/photos/zaragozaantigua/19440935908/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25154, 'Palacio de Morata a├▒os 30', 'Acuarela de Ambrosio Ruste que muestra la portada del palacio de los condes de Morata o de los Luna, luego Audiencia, en el Coso Alto. Fuente: L├íminas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65392800, -0.88369300, '0101000020E61000003788D68A3647ECBF27F8A6E9B3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31627339493.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31627339493.webp', 'https://www.flickr.com/photos/zaragozaantigua/31627339493/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25687, 'Plaza de Salamero 1974', 'Derribo del inmueble del n┬║ 2 de la calle del Requet├® Aragon├®s, construido a principios del siglo cuando era la calle del Cinco de Marzo, posiblemente dise├▒ado por Fernando de Yarza, en una vista desde la plaza de Miguel Salamero. Su solar lo ocupar├¡a luego un moderno edificio. A la derecha, Bar el Pozal, y una puertecita con celos├¡as en ladrillo de acceso al colegio de Santa Rosa. A la izquierda, puesto de casta├▒era con saco de carb├│n.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65197600, -0.88374400, '0101000020E6100000BF28417FA147ECBF71E316F373D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14851661532.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14851661532.webp', 'https://www.flickr.com/photos/zaragozaantigua/14851661532/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25688, 'Santiago el Mayor 1940', 'AHPZ-Archivo Coyne, Manuel Coyne, 1940. Fachada y torres de la Iglesia de San Ildefonso (o de Santiago el Mayor).', 1940, 1940, 1940, 'Anos 40', 'CENTRO', 41.65224800, -0.88507500, '0101000020E6100000FB3A70CE8852ECBFD270CADC7CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14857858436.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14857858436.webp', 'https://www.flickr.com/photos/zaragozaantigua/14857858436/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25689, 'Calle de San Ildefonso 1930', '"Iglesia de Santiago".', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65237600, -0.88513400, '0101000020E6100000397CD2890453ECBFFF58880E81D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14875365745.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14875365745.webp', 'https://www.flickr.com/photos/zaragozaantigua/14875365745/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25690, 'Plaza de Salamero 1974', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/Octubre 1974. Imagen de la entrada a la remodelada Plaza de Salamero desde la flamante y nueva Avenida de C├®sar Augusto, con la iglesia de Santiago el Mayor al fondo. Los solares, a izquierda y derecha de la Plaza, est├ín pendientes de ser construidos con modernos bloques de viviendas y de oficinas.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65252900, -0.88492500, '0101000020E6100000A835CD3B4E51ECBF8658FD1186D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14882405296.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14882405296.webp', 'https://www.flickr.com/photos/zaragozaantigua/14882405296/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25691, 'Torre derecha Santiago 1972', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/Noviembre 1972. La iglesia de Santiago el Mayor es el ├║nico vestigio del antiguo Convento de San Ildefonso de la Orden de Santo Domingo. Es la iglesia barroca de mayores proporciones en Zaragoza. El convento fue fundado por don Alonso de Villalpando, inici├índose su construcci├│n en 1651. Los trabajos se desarrollan a lo largo de la segunda mitad del siglo XVII. El convento fue abandonado tras la Desamortizaci├│n de Mendiz├íbal en 1836. En 1860 la c├║pula original qued├│ destruida tras recibir el impacto de un rayo. Se rehizo siguiendo la est├®tica barroca y en 1964-1965 se restaur├│ y cubri├│ con tejas vidriadas de Manises, creando un efecto similar al de las c├║pulas de la Bas├¡lica del Pilar. En 1902 el edificio pasa a ser la sede de la parroquia de Santiago, cuya iglesia hab├¡a sido derribada. En la d├®cada de 1970, el arquitecto Fernando Chueca Goitia recreci├│ las torres de la fachada a├▒adiendo los cuerpos de remate, dentro de una est├®tica entre lo barroco-clasicista, y lo neoclasicista. En la imagen, andamiajes de la obra de recrecimiento en la torre derecha. Las obras de derribo para la apertura de la Avenida de C├®sar Augusto, contin├║an.', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65247300, -0.88480100, '0101000020E6100000A4FACE2F4A50ECBFF2423A3C84D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14902109661.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14902109661.webp', 'https://www.flickr.com/photos/zaragozaantigua/14902109661/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25693, 'Avenida C├®sar Augusto 1974', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/Octubre 1974. Imagen de la flamante y nueva Avenida de C├®sar Augusto, en el tramo de la iglesia de Santiago el Mayor, a su derecha, y la remodelada Plaza de Salamero, a su izquierda.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65272900, -0.88473200, '0101000020E61000008330B77BB94FECBF4D13B69F8CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14905366675.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14905366675.webp', 'https://www.flickr.com/photos/zaragozaantigua/14905366675/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25694, 'C├®sar Augusto 1974', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 08/09/1974. Imagen desde la nueva Avenida de C├®sar Augusto de las obras de urbanizaci├│n del entorno del antiguo Hospital Militar. A la derecha, la iglesia de Santiago el Mayor. La calle que se abre es la de Cam├│n Aznar, y la calle del fondo, con las ventanas del bloque de viviendas a├║n con las marcas en los cristales, Ram├│n y Cajal. A la izquierda, solares donde pronto se levantar├ín nuevos bloques habitacionales de 7 y 8 alturas, junto al Hotel Corona de Arag├│n.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65223200, -0.88522000, '0101000020E6100000DD7BB8E4B853ECBFCCB392567CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14945608811.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14945608811.webp', 'https://www.flickr.com/photos/zaragozaantigua/14945608811/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25695, 'Hospital militar 1930', 'Archivo V├¡ctor Bar├│n. 1930 "Imagen del desaparecido hospital militar de la calle de San Ildefonso, al lado de la iglesia de Santiago. Funcion├│ como tal desde 1816 hasta 1958, en que se inaugur├│ el del paseo de Isabel La Cat├│lica."', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65269700, -0.88487700, '0101000020E61000006571FF91E950ECBF429946938BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14957750336.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14957750336.webp', 'https://www.flickr.com/photos/zaragozaantigua/14957750336/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25696, 'Plaza de Salamero 1972', '1972. Imagen de la Plaza de Salamero, remodelada y convertida en Postal tras la reciente construcci├│n del aparcamiento subterr├íneo. La vista se orienta hacia la manzana que da al Coso. A la derecha, la calle Teniente Coronel Valenzuela. A la izquierda, espacios en v├¡as de extinci├│n: el tramo de la calle Azoque que conectaba el Coso con la Plaza, la Plaza de Luis Sant├íngel, y la calle Ser├│n. Lo mismo le sucede a la manzana a la izquierda de la Plaza, menguada para ensanchar la Avenida de C├®sar Augusto. Aunque, en este caso, las nuevas alturas superar├ín todo lo visto anteriormente. Todo.', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65212000, -0.88412000, '0101000020E610000026AAB706B64AECBFA4880CAB78D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14977412465.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14977412465.webp', 'https://www.flickr.com/photos/zaragozaantigua/14977412465/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25697, 'Hospital de San Ildefonso 1925', 'Durante los enfrentamientos b├®licos del Reino de Espa├▒a con el I Imperio Franc├®s a comienzos del XIX, y ante el colapso de las instalaciones sanitarias de la ciudad, el convento de San Ildefonso fue habilitado como "Hospital de Sangre de San Ildefonso" para cuidado y atenci├│n a heridos por causa de la guerra. Este hospital provisional o de campa├▒a, al igual que ocurri├│ con el de Convalecientes, con el paso de los a├▒os terminar├¡a siendo un hospital militar fijo denominado "Hospital Militar de San Ildefonso", instalaci├│n que permaneci├│ en funcionamiento 150 a├▒os. Se trata de la fachada principal del antiguo Hospital Militar de San Ildefonso, establecido desde el principio del siglo XIX en el antiguo y hom├│nimo convento, con la iglesia de Santiago (antigua del convento), a la derecha. El espacio de primer t├®rmino era la plaza de San Ildefonso a espaldas de la calle de la Biblioteca, con la calle de San Ildefonso a la derecha. Entre tanto solemne ladrillo barroco, unos pardales hacen una pausa en sus juegos y posan en la rinconera del centro de la imagen. La parte trasera del hospital daba a la calle de Ram├│n y Cajal. Este hospital estuvo aqu├¡ operativo hasta su derribo y traslado a la V├¡a Ib├®rica en los a├▒os 60 del pasado siglo XX.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65228800, -0.88531100, '0101000020E6100000F23FF9BB7754ECBF60C9552C7ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14981591729.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14981591729.webp', 'https://www.flickr.com/photos/zaragozaantigua/14981591729/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21935, 'La monta├▒a de Bruil 1941', '"Parque de Torre de Bruil antes de la reforma." En la calle Asalto 38 (tramo entre Palomar y Alonso V) ten├¡a su entrada la Torre de Bruil, cuyo edificio-vivienda con fachada a la calle no hac├¡a justicia al ampl├¡simo y exuberante recinto al aire libre orientado hacia el Huerva, con un parque y jardines muy destacables y afamados. Fue ordenada su construcci├│n por el due├▒o del terreno, Juan Faustino Bruil, siendo terminada la obra en 1844. Constaba la Torre de una "monta├▒a rusa" de 25 metros de altura construida a modo de atalaya desde la que dominar visualmente el entorno. Se ascend├¡a mediante una escalera de madera adosada. A la monta├▒a tambi├®n se hab├¡an horadado varias cavidades a modo de cuevas. Fuente: Archivo Municipal de Zaragoza. Aportada por Gerardo Sancho Ramo. 1941.', 1941, 1941, 1941, 'Anos 40', 'LAS FUENTES', 41.64992300, -0.86800500, '0101000020E61000009F76F86BB2C6EBBF88F546AD30D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15178171317.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15178171317.webp', 'https://www.flickr.com/photos/zaragozaantigua/15178171317/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25702, 'Calle Azoque c.1972', 'Tramo de la calle del Azoque entre el principio de la calle de Pignatelli y el callej├│n del Ser├│n, a la izquierda y fuera de plano. A la derecha, restos de la plazuela de Luis Sant├íngel encajonada entre las calles de Agust├¡n Palomeque, y de la Morer├¡a, desde donde en primer plano aparece un ciclista . Tras derribos y ensanches, el tramo de la calle del Azoque que al fondo arranca desde el Coso asemeja una l├║gubre calleja: es lo que sucede cuando se alteran la escala y proporciones urbanas. Durante siglos, y hasta la irrupci├│n del tr├ífico rodado de masas, este fue el tradicional modelo urban├¡stico de este y otros espacios de la ciudad. Poco despu├®s, para dar continuidad a la avenida Imperial como urbana autov├¡a entre el puente de Santiago y la puerta del Carmen, la trinchera de asfalto y tr├ífico rodado transformar├¡a radicalmente esta zona de la vieja Morer├¡a.', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65361900, -0.88408800, '0101000020E61000004E27D9EA724AECBFA98592C9A9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22551445163.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22551445163.webp', 'https://www.flickr.com/photos/zaragozaantigua/22551445163/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25706, 'Calle de Valenzuela c.1977', 'Calle del Teniente Coronel Valenzuela desde la plaza de Miguel Salamero. A la derecha, inmediato y en servicio desde los a├▒os 20, el Hotel Lafuente. A continuaci├│n, la rotunda presencia del Banco de Arag├│n, de la que se destaca la sonora bocina que originalmente estuviera sobre la antigua sede de este banco, frente a la calle de Alfonso I. A la izquierda, esquina del colegio de las madres Escolapias. Al fondo, el edificio del Cine Coso.', 1977, 1977, 1977, 'Anos 70', 'CENTRO', 41.65266400, -0.88324100, '0101000020E610000011902FA18243ECBF66A3737E8AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23984078893.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23984078893.webp', 'https://www.flickr.com/photos/zaragozaantigua/23984078893/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25707, 'Plaza Salamero 1972', 'La plaza de Miguel Salamero, antigua de Santa Fe, en una colorista imagen capturada en altura desde el lado sur durante la ├║ltima fase de urbanizaci├│n de este espacio, tras las obras de construcci├│n del aparcamiento subterr├íneo con capacidad para 340 veh├¡culos. A la izquierda, tramo de la calle del Azoque delimitado entre las calles de Telesforo Peromarta, al fondo, y del Doctor Mariano G├│mez Ulla, fuera de plano, con vista parcial de la manzana de viviendas derribadas poco despu├®s. En el centro de la escena, la manzana comprendida entre la calle del Azoque y la del Teniente coronel Valenzuela, fuera de plano, con una escalonada vista del colegio de las madres Escolapias y la barroca c├║pula de la anexa iglesia de la Manter├¡a; del edificio de Seguros La Adri├ítica, detr├ís; y de la vertical estructura del inmueble en construcci├│n del n┬║ 24 del Coso Alto.', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65243100, -0.88393900, '0101000020E6100000121615713A49ECBFC3F2E7DB82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24187675980.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24187675980.webp', 'https://www.flickr.com/photos/zaragozaantigua/24187675980/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25709, 'Colegio Santa Rosa 1794', 'Plano del colegio a construir en los terrenos del convento de Santa Rosa. Pedro de Zeballos y Jos├® de Yarza, Zaragoza, 1794. El convento de Santa Rosa de las Misioneras Dominicas del Rosario, cuyos or├¡genes se remontan a 1674, comienza a ofrecer servicios educativos para ni├▒as en 1781. Pronto surge la necesidad de ampliar sus instalaciones mediante un nuevo edificio anexo, que refleja el plano, orientado de sur a norte. A la derecha, entrada principal desde la calle del Carmen. Arriba, pared recayente a la calle de San Jer├│nimo. Abajo, accesos a la iglesia y convento. El solar que ocupaban convento, iglesia y colegio sigue ocupado parcialmente hoy por un moderno colegio de la misma Orden, entre la plaza de Salamero (antigua de Santa Fe) y las calles de Azoque y San Jer├│nimo. Fuente visual: DARA/AHPZ.', 1794, 1794, 1794, 'Siglo XIX', 'CENTRO', 41.65183800, -0.88415300, '0101000020E61000001421753BFB4AECBF2025766D6FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24610753974.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24610753974.webp', 'https://www.flickr.com/photos/zaragozaantigua/24610753974/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25711, 'Calle San Ildefonso 1903', 'Calle de San Ildefonso, con la barroca iglesia del antiguo convento de San Ildefonso al fondo, redenominada en 1902 "Santiago el Mayor", heredando esa denominaci├│n de la clausurada iglesia de Santiago de la calle Don Jaime I. Detr├ís, el Hospital Militar. A la izquierda de la calle, inmediato, el taller de herrer├¡a mec├ínica de Ram├│n Vigata. A la derecha, viviendas de la calle, en el tramo entre las calles de Peromarta, y Arco de San Ildefonso. A la espalda del fot├│grafo, la calle de Peromarta. Al fondo, hacia la izquierda, se abr├¡a la calle de la Biblioteca. Fuente visual: www.facebook.com/groups/fotosantiguasdezaragoza/permalink...', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65303200, -0.88480800, '0101000020E610000044A7E7DD5850ECBFE99E758D96D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25467142845.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25467142845.webp', 'https://www.flickr.com/photos/zaragozaantigua/25467142845/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25714, 'Plaza Salamero 1972', 'Foto: Javier Torres. Vista, al fondo, del entorno de la plaza de Salamero desde lo que ser├í la avenida de C├®sar Augusto, en pleno proceso de derribo de la calle de Azoque y alrededores. Fuente: www.facebook.com/photo.php?fbid=166447690484841&set=g...', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65243700, -0.88476600, '0101000020E6100000899B53C90050ECBFA5D93C0E83D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30733963866.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30733963866.webp', 'https://www.flickr.com/photos/zaragozaantigua/30733963866/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25860, 'Teatro Fleta 2001', 'Aspecto del esqueleto del teatro Fleta de Zaragoza (1955) en 2001, tras su derribo para "remodelarlo". La previsi├│n de reinauguraci├│n estaba fijada en 2003. Fuente: Cr├│nica de Zaragoza. Ayuntamiento de Zaragoza, 2002.', 2001, 2001, 2001, 'Siglo XXI', 'CENTRO', 41.65163900, -0.88518800, '0101000020E610000005F9D9C87553ECBF2AE620E868D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18548452388.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18548452388.webp', 'https://www.flickr.com/photos/zaragozaantigua/18548452388/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25864, 'Teatro Fleta 2011', 'Panor├ímica del solar del antiguo Teatro Fleta (1955), derribado para "remodelarlo" en el cambio de siglo, prevista su reinauguraci├│n en 2003. A la derecha, avenida de C├®sar Augusto. Fuente: www.andalan.es/?p=3881', 2011, 2011, 2011, 'Siglo XXI', 'CENTRO', 41.65163900, -0.88518800, '0101000020E610000005F9D9C87553ECBF2AE620E868D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25528911076.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25528911076.webp', 'https://www.flickr.com/photos/zaragozaantigua/25528911076/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25867, 'Teatro Fleta 2009', 'Foto: Pedro Etura. Inusual vista urbana elevada tomada el 23 de enero de 2009 desde la avenida de C├®sar Augusto, que muestra el esqueleto del Teatro Fleta, derribado en 2001 para "remodelarlo". M├ís al fondo, traseras de los edificios de la calle de Azoque y del paseo de la Independencia. Fuente: Heraldo de Arag├│n.', 2009, 2009, 2009, 'Siglo XXI', 'CENTRO', 41.65166800, -0.88523800, '0101000020E610000076A565A4DE53ECBFC4EC65DB69D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32116836154.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32116836154.webp', 'https://www.flickr.com/photos/zaragozaantigua/32116836154/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25869, 'Teatro Iris 1954', 'Imagen capturada en el vest├¡bulo del nuevo Teatro Iris, luego Teatro Fleta, con vista parcial del mural realizado por Francisco Javier Ciria Escartivol para decorar el irregular friso de 35 m sobre las puertas de ingreso al patio de butacas. Fue terminado a finales de 1954 con nueve paneles que destacaban por su descontextualizada tem├ítica relacionada con la denominada "pintura biol├│gica" practicada por este autor, que en este caso muestra una interesante galer├¡a de animales de la fauna ib├®rica, con representaciones de mam├¡feros como sarrios, cabras montesas, gamos y ciervos; aves como perdices, picarazas, abubillas, pitos verdes y una grulla. Adem├ís, entre esta galer├¡a se incluyen dos mujeres. Tras el cierre del Teatro Fleta en 1999, las pinturas del mural fueron arrancadas en octubre de 2001 durante el proceso de "rehabilitaci├│n" del teatro, para lo cual fue troceado en quince paneles y almacenado en la antigua Universidad Laboral de Zaragoza. En 2009 fueron trasladadas a las nuevas instalaciones de la Escuela Taller de Restauraci├│n del Gobierno de Arag├│n sita en PLAZA, donde se las restaur├│ y almacen├│ a la espera de que el Teatro Fleta sea rehabilitado... cuando sea. Las pinturas de la imagen se corresponden con los originales paneles n┬║ 6 y 7 (actuales n┬║ 9 y 10) de la zona central del mural, y en ellos aparecen las figuras de varios ciervos y de una mujer en din├ímica composici├│n.', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.65163100, -0.88523600, '0101000020E610000049BDA772DA53ECBFA70705A568D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50652197202.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50652197202.webp', 'https://www.flickr.com/photos/zaragozaantigua/50652197202/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25925, 'Coso Alto c.1900', 'Imagen del primer tramo alto del Coso, posiblemente capturada desde la altura de la antigua Casa de las Monas, en cuyos bajos estaba la central interurbana de tel├®fonos. A la izquierda, la Audiencia y la calle hom├│nima. A la derecha, tramo del Coso entre la calle del Azoque y plaza de la Constituci├│n. Sobre el firme, tendido de la tranviaria l├¡nea de Circunvalaci├│n. Fuente visual: Fototipia Lucas Escol├í para edici├│n postal de la Uni├│n Postal Universal, en www.ebay.es/', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.65394400, -0.88361800, '0101000020E61000008E0585419946ECBF2DB5DE6FB4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34002372360.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34002372360.webp', 'https://www.flickr.com/photos/zaragozaantigua/34002372360/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21672, 'Sala de disecci├│n c.1934', 'Foto: Colecci├│n Jos├® Luis Cintora. Pabell├│n de la sala de disecci├│n del Hospital Provincial de Zaragoza, construida en 1873 y donde trabajaba Santiago Ram├│n y Cajal. Se trata de las traseras del edificio, hoy calle Doctor Fleming. Fue demolido en 1958. Fuente: www.rafaelcastillejo.com', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.65125700, -0.88938700, '0101000020E6100000079ACFB9DB75ECBF4225AE635CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14817786487.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14817786487.webp', 'https://www.flickr.com/photos/zaragozaantigua/14817786487/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21675, 'Enfermeras y ametralladora 1938', 'AHPZ. Estudio Coyne. Manuel Coyne. 1938. Zaragoza, como important├¡sima ciudad de retaguardia en poder de los nacionalistas, se llen├│ de hospitales en los que atender a los heridos del frente. En la imagen, enfermeras del Hospital Provincial de Zaragoza posando con ni├▒os junto a una ametralladora pesada Hotchkiss, colocada con funciones antia├®reas contra las incursiones de los aviones republicanos. En mayo de 1937, durante uno de los bombardeos, un par de bombas hab├¡an ca├¡do cerca del huerto del Hospital.', 1938, 1938, 1938, 'Anos 30', 'CENTRO', 41.65223200, -0.88760700, '0101000020E6100000E86B96CB4667ECBFCCB392567CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14839180729.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14839180729.webp', 'https://www.flickr.com/photos/zaragozaantigua/14839180729/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21695, 'Iris Park c.1932', 'Propaganda del gran complejo Iris Park de Zaragoza, inaugurado en 1931, en la que se reproduce un dibujo de los edificios que lo compon├¡an. Estaba situado entre las calles de Azoque y Ram├│n y Cajal, sobre el trazado de la actual avenida de C├®sar Augusto en su tramo del Teatro Fleta, que se construy├│ en 1955 en el solar del Iris, recibiendo su nombre en un principio. Antes de la construcci├│n de este centro de ocio (con, entre otras cosas, cine -el m├ís grande de Zaragoza-, teatro y pista de patinaje), ocupaban el solar unos lavaderos p├║blicos, con el Hospital Militar (antiguo convento de San Ildefonso) al norte, el Hospital Provincial al oeste y el Cuartel de Artiller├¡a al sur. Fuente: www.raimundolanas.com/vida.htm', 1932, 1932, 1932, 'Anos 30', 'CENTRO', 41.65171900, -0.88554200, '0101000020E61000007880272D5C56ECBF469737876BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15358527522.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15358527522.webp', 'https://www.flickr.com/photos/zaragozaantigua/15358527522/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21949, 'Ram├│n y Cajal 1949', '"Fachada del Hospital Provincial de Nuestra Se├▒ora de Gracia de la Beneficencia de Zaragoza". En 1677 fue fundado el Hospital de Nuestra Se├▒ora de la Piedad, llamado de Convalecientes por estar destinado a enfermos en proceso de curaci├│n, y que precisaban "convalecer". Fue realizado en formas y maneras barrocas, junto a la resplandeciente iglesia de su interior. A mediados del XIX, ya bajo responsabilidad de la Diputaci├│n Provincial, se realizaron obras para ampliar y mejorar las instalaciones hospitalarias, d├índole el aspecto exterior que hoy conserva. En la imagen, aspecto del pabell├│n situado a la izquierda de la iglesia, al que peatonalmente se accede desde la calle Ram├│n y Cajal, y el tr├ífico rodado puede hacerlo por un paso a la izquierda. Tras el derribo del antiguo edificio de la Diputaci├│n Provincial, el reloj que hasta entonces daba la hora desde su alabeado y caracter├¡stico front├│n superior, ser├í migrado hasta el decorativo ├│culo del front├│n que vemos. Fuente visual: www.bancodeimagenesmedicina.es/', 1949, 1949, 1949, 'Anos 40', 'CENTRO', 41.65177500, -0.88697400, '0101000020E6100000ADDF4C4C1762ECBFDAACFA5C6DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17186671109.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17186671109.webp', 'https://www.flickr.com/photos/zaragozaantigua/17186671109/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21905, 'Las Palmeras azules 1936', 'Imagen capturada en los pinares del cabezo de Buenavista inmediatos al "restaurant Las Palmeras" durante el almuerzo que el gremio de hoteleros obsequi├│ a las 3.000 afiliadas a la Secci├│n Femenina de Falange Espa├▒ola de las JONS de Zaragoza y provincia (centurias de Calatayud, Tarazona, Borja, Ejea, Cari├▒ena, Belchite, La Almunia, Pina y Sos), tras el homenaje "a los muertos de Espa├▒a" y a "nuestra Santa Patrona la Virgen del Pilar" realizado el domingo 6 de septiembre de 1936. Dicho homenaje consisti├│ en una marcial misa de campa├▒a en el paseo de Pamplona, un desfile urbano de ida hasta el templo del Pilar que termin├│ en la capilla de la "Virgen de Arag├│n", y otro de regreso hasta la Facultad de Medicina y Ciencias. Hubo, adem├ís, un homenaje en el cementerio de Torrero en la tumba de Marina Moreno, "la m├írtir" local de Falange. Durante la sobremesa del almuerzo hubo ocasi├│n para una ilustrativa alocuci├│n de Jes├║s Muro, jefe provincial de Falange.', 1936, 1936, 1936, 'Anos 30', 'UNIVERSIDAD', 41.63336600, -0.89310000, '0101000020E6100000DCD781734694ECBFFD32182312D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51728547058.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51728547058.webp', 'https://www.flickr.com/photos/zaragozaantigua/51728547058/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22122, 'Calle Padre Juan Bonal 1958', 'Desde 1873, en la Huerta Alta del Hospital Provincial, junto al paseo de la Ronda, funcionaba el "Anfiteatro, Sala de Disecci├│n y Capilla para Cad├íveres" del Hospital, donde trabajara un tiempo Santiago Ram├│n y Cajal. En 1912 fueron construidos enfrente los Talleres del Hogar Pignatelli, y se abri├│ un nuevo camino para conectar el paseo de la Ronda, y la calle de la Misericordia. En 1943, este camino recibi├│ el nombre de Padre Juan Bonal (fundador de la Orden de las Hermanas de la Caridad de Santa Ana, cuya Casa General y Noviciado estaba cerca). En el momento de realizaci├│n de la imagen, se estaba reurbanizando la zona, antes de construir la nueva Delegaci├│n Provincial de Trabajo. Por ello, esta "Capilla para Cad├íveres" (sin parroquia hace ya tiempo) y su reconocible ├íbside semicircular, fueron demolidos integralmente. Al fondo, el paseo de Mar├¡a Agust├¡n, con visual de los antiguos edificios de viviendas entre el cuartel de Trinitarios, y la calle de la Industria. A finales de 1960, este vial ser├¡a redenominado "Doctor Fleming". Fuente visual: Jarke, Archivo P├║blico Municipal.', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.65158300, -0.88950600, '0101000020E610000099107349D576ECBF96D05D1267D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22727777828.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22727777828.webp', 'https://www.flickr.com/photos/zaragozaantigua/22727777828/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22385, 'Paseo de Mar├¡a Agust├¡n c.1960', 'A├®rea imagen de la zona del paseo de Mar├¡a Agust├¡n y la reurbanizada y ampliada nueva calle del Doctor Fleming. En primer t├®rmino, ya ha sido derribado el antiguo "Anfiteatro, Sala de Disecci├│n y Capilla para Cad├íveres" del Hospital Provincial. All├¡ se levantar├í despu├®s la nueva sede de la Delegaci├│n Provincial de Trabajo. Enfrente, los Talleres del Hogar Pignatelli, y los nuevos bloques para funcionarios. En primer├¡simo plano, a la izquierda, el cuartel de Trinitarios. Arriba, a la izquierda, el cuartel del Cid. Adem├ís: el Coso de la Misericordia, el Hogar Pignatelli, la Casa y Noviciado de las Hermanas de la Caridad de Santa Ana, la Huerta del Hospital Provincial, el Cuartel de Sangenis, el Parque de Artiller├¡a, la plaza del Portillo... Fuente visual: "Los talleres del Hogar Pignatelli".', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.65157300, -0.89006500, '0101000020E6100000410E4A98697BECBF72FA7ABE66D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22525920433.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22525920433.webp', 'https://www.flickr.com/photos/zaragozaantigua/22525920433/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22504, 'Calle del Doctor Fleming 1960', 'Imagen a├®rea de la zona donde hab├¡an sido construidos los cuatro nuevos bloques de viviendas para funcionarios junto al paseo de Mar├¡a Agust├¡n, en terrenos del Hospicio y Hospital Provincial. La reurbanizaci├│n de este entorno propici├│ tambi├®n la apertura de la nueva calle del Doctor Fleming, en primer t├®rmino, como conexi├│n r├ípida entre la de Madre Rafols y el paseo. Destacan los restos del antiguo Anfiteatro, Sala de Disecci├│n y Capilla para Cad├íveres del Hospital Provincial, frente a los Talleres del Hogar Pignatelli. Al otro lado del paseo perduran los restos del cuartel de Trinitarios. En la parte superior, el Grupo escolar Joaqu├¡n Costa, el Refugio, el cuartel de la Polic├¡a Armada y la estaci├│n de ferrocarril de Campo Sepulcro, donde destaca el gran dep├│sito de locomotoras de vapor. A la derecha, la triangular manzana de viviendas militares entre el paseo de Mar├¡a Agust├¡n y la avenida de Anselmo Clav├®. Frente a ellas, el Hogar Pignatelli, y en la parte inferior y a la derecha la Casa y Noviciado de las Hermanas de la Caridad de Santa Ana, con su gran zona de jardines. Entre los planes para esta zona constaba el proyecto de una gran plaza con jardines "para embellecer la entrada a la ciudad por la estaci├│n del Mediod├¡a (sic)". La fijaci├│n por "embellecer" la ciudad inclu├¡a cambiar el nombre de la veterana estaci├│n de Campo Sepulcro, tal vez por su mortuoria referencia. Mientras tanto, el parque previsto no pasar├¡a de las musas al teatro de la realidad.', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.65185500, -0.89018200, '0101000020E6100000A69C2FF65E7CECBFF65D11FC6FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50045877448.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50045877448.webp', 'https://www.flickr.com/photos/zaragozaantigua/50045877448/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22570, 'C├│lera 1971', 'Fila para vacunaci├│n del c├│lera en la Jefatura Provincial de Sanidad, en la calle de Ram├│n y Cajal n┬║ 68. En los a├▒os setenta aparecieron varias epidemias de c├│lera en Espa├▒a, la primera de las cuales afect├│ en 1971 a Zaragoza, Barcelona, Valencia y Murcia. Como consecuencia, hubo una epidemia (positiva) de inversiones y actuaciones p├║blicas para mejorar la calidad del agua corriente y el alcantarillado en los barrios obreros de la periferia.', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.65118200, -0.88655500, '0101000020E6100000745E6397A85EECBF37DF88EE59D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15326736006.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15326736006.webp', 'https://www.flickr.com/photos/zaragozaantigua/15326736006/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22601, 'V├¡a Imperial 1973', '"En esta zona se construir├í un gran aparcamiento subterr├íneo", foto Monge, 1973. El aparcamiento al que se refiere el titular "ocupar├í la zona que queda sin urbanizar del Plan Parcial Especial de San Ildefonso. Abarcar├í desde el cruce entre General Sanjurjo y Capit├ín Portol├®s hasta la zona situada ante la iglesia de Santiago actual salida a la plaza de Salamero por la V├¡a Imperial". En la imagen, a la izquierda, el hotel Corona de Arag├│n; a la derecha, el teatro Fleta; al fondo, torre├│n derecho del antiguo palacio de Luna-Morata, o Audiencia. Fuente: Diario Amanecer, 11 de mayo de 1973.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65194200, -0.88548400, '0101000020E61000005133A48AE255ECBFC571E0D572D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18753121924.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18753121924.webp', 'https://www.flickr.com/photos/zaragozaantigua/18753121924/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22698, 'Nocturna San Ildefonso 1971', 'Nocturna imagen, desde cierta altura, del entorno del Hospital Provincial, la calle Ram├│n y Cajal, y la iglesia parroquial de San Ildefonso. Al fondo, el reflejo selenita del sol, en una toma irrepetible poco despu├®s, cuando a la plaza de Salamero, antigua de Santa Fe, le crezca un referencial y palmario rascacielos. A la izquierda, entre tinieblas, la linterna que culmina la c├║pula de la barroca iglesia del antiguo hospital de convalencientes, levantada all├í por el siglo diez y siete. Fuente visual: Patti Larson Photo, en www.flickr.com', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.65183300, -0.88713400, '0101000020E6100000E36DA5D76663ECBF0FBA84436FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27366926373.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27366926373.webp', 'https://www.flickr.com/photos/zaragozaantigua/27366926373/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23106, 'Fernando Arrabal 2000', 'El escritor melillense Fernando Arrabal (1932), ante uno de sus retratos, pintados por diversos autores y expuestos en el museo Pablo Serrano en febrero de 2000. Fuente: Agencia EFE.', 2000, 2000, 2000, 'Siglo XXI', 'CENTRO', 41.65157300, -0.89006500, '0101000020E6100000410E4A98697BECBF72FA7ABE66D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24523279782.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24523279782.webp', 'https://www.flickr.com/photos/zaragozaantigua/24523279782/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23149, 'Calle Albareda 2009', 'Foto: Juan Carlos Arcos. Construcci├│n en febrero de 2009 del nuevo edificio de la sede del Ministerio de Econom├¡a, en la calle de Jos├® Luis Albareda 18, junto a la Delegaci├│n de Hacienda. Las obras se iniciaron en 2005 y concluyeron en noviembre de 2009. Fuente: Heraldo de Arag├│n.', 2009, 2009, 2009, 'Siglo XXI', 'CENTRO', 41.65161200, -0.88837100, '0101000020E6100000C6DFF604896DECBF30D7A20568D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32167848144.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32167848144.webp', 'https://www.flickr.com/photos/zaragozaantigua/32167848144/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
